window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science>1994>1>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Define the term land tenure system and give four examples.","images":[],"marking_scheme":"Land tenure is defined as the system of land ownership by individual, family or community either for temporary or permanent use. Four examples of land tenure systems are: (i) Communal (ii) Rent (iii) Inheritance (Iv) Pledge or gift.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>1>b>i","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"i","group":"","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Discuss briefly Land Use Decree","images":[],"marking_scheme":"The Land Use Decreee of 1978 vested land ownership in the country in the hands of the Federal Government of Nigeria. The state governments were empowered to allocate land to individuals above 21 years of age on behalf of the Federal Government. For a person to claim ownership of land, such a person must obtain a certificate of occupant which will guarantee the true ownership of such land.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>1>b>ii","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"ii","group":"","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"State two advantages and two disadvantages of the decree","images":[],"marking_scheme":"Two advantages of the decree are:   (1) It makes it easier for people to acquire land for large scale farming. (2) It controls the excesses of land speculators    Two disadvantage of the decree are: (1) Only the rich and influential individuals exploit the decree to acquire more lands   (2) It takes long time for individuals to obtain land from the government.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>2>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"What is farm surveying?","images":[],"marking_scheme":"Farm surveying is a series of activities, mainly measurements, performed in the field to locate the farm land, delineate its boundaries, determine its size and produce a map of the farmland.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>2>b>i","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"i","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"List six surveying instruments.","images":[],"marking_scheme":"(i) Prismatic compass   (ii) Gunter's chain   (iii) Measuring tape   (iv) Ranging pole   (v) Theodolite   (vi) Beacon/Pillars","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>1994>2>b>ii","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"ii","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Write short notes on any four surveying instruments listed in (i)","images":[],"marking_scheme":"(i) Ranging poles: These are wood or metal poles used in marking spots or stations during surveying.    (ii) Gunter's chain: This is a surveyor's chain of 100 links. 22 meters long used to measure a piece of land.    (iii) Measuring tapes: These are used in taking short or detailed measurements    (iv) Prismatic compass: This is used to measure horizontal angles between a reference median and a point of interest in order to find the orientation of the point and its bearing.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>3>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Define the term irrigation","images":[],"marking_scheme":"Irrigation is defined as the artificial application of water to the soil for farming purposes.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>1994>3>b","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"List six sources of water for irrigation","images":[],"marking_scheme":"(i) Rivers   (ii) Lakes   (iii) Streams   (iv) Dams   (v) Bore holes   (vi) Ponds","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>1994>3>c","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Give three reasons why irrigation schemes are necessary in Nigeria.","images":[],"marking_scheme":"(i) It ensures early planting of crops.   (ii) It ensures greater productivity  of crops.   (iii) It corrects soil salinity.   (iv) It enables farmers to grow crops throughout the year.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>3>d","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"d","group":"","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"State two similarities and three differences between sprinkler and surface irrigation","images":[],"marking_scheme":"Two similarities between surface and sprinkler irrigation are:   (i) Both are artificial methods of applying water to crops.     (ii) Both require water pump to lift water from source.    Three differences between surface and sprinkler irrigation are:  Surface irrigationSprinkler irrigation It is cheapIt is expensiveIt requires gentle slopeIt is suitable for lands with all kinds of slopesIt is easy to operateIt requires skill","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>4","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"4","group":"","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"List and discuss briefly four climatic factors that affect agricultural production in Nigeria","images":[],"marking_scheme":"Four climatic factors affecting agricultural production in Nigeria include: (a) Rainfall (b)Temperature (c) Wind (d) Sunlight.    (a) Rainfall: (i) It determines the seasons in Nigeria i.e rainy and dry season. (ii) It determines when crops can be planted. (iii) It determines the distribution of vegetation. (iv) Excessive rainfall causes erosion.    (b) Temperature: (i) It is necessary for germination of seeds. (ii) It affects the growth and maturity of crops. (iii) It affects the ripening of fruits. (iv) Excessive temperature results in evapo-transpiration.    (c) Wind: (i) It determines the seasons in Nigeria. (ii) The South -East wind brings rain (iii) It aids the pollination of flowers. (iv) It can cause erosion.    (d) Sunlight: (I) It is required by plants for photosynthesis. (ii) It affects the growth rate and productivity of crops. (iii) It affects photoperiodism i.e. day length of crops. (iv) It affects productivity in poultry.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>5>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT~~CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"Explain what is meant by natural grassland","images":[],"marking_scheme":"Natural grassland refers to any area of land on which sparsely distributed low forest trees and abundance of grasses suitable for grazing are present without being cultivated by farmers. Examples are the Savanna areas in Nigeria.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>5>b","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"State five characteristics of natural grassland","images":[],"marking_scheme":"Characteristics of natural grasslands are: (i) The soils are usually low in fertility. (ii) Grasses growing cannot be easily eradicated. (iii) Grasses are resistant to trampling by animals. (iv) The soils are well drained. Grasses are resistant to drought.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>5>c","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"List four grasses commonly found in natural grasslands.","images":[],"marking_scheme":"Four grasses commonly found in natural grassland are:   (i) Guinea grass   (ii) Elephant grass   (iii) Southern Gamba   (iv) Giant star grass.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>1994>5>d","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"d","group":"","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"List three pasture legumes commonly found in natural grasslands.","images":[],"marking_scheme":"(i) Centrosern pubescens (or centro)  (ii) Calopogonium mucunoides (or Calopo)   (iii) Mucuna utilis (or Mucuna).","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science>1994>6>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"FARMING SYSTEMS","question":"Define the term Taungya system.","images":[],"marking_scheme":"Taungya System is the growing of both trees or forest trees and crops on the same piece of land at the same time.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>6>b","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"FARMING SYSTEMS","question":"State five conditions that favour the practice of taungya system in Nigeria.","images":[],"marking_scheme":"(i) scarcity of land   (ii) Over population   (iii) unemployment   (iv) Government policy   (v) Low standard of living.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>6>c>i","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"i","group":"","topic":"FARMING SYSTEMS","question":"State two advantages of the system to each of the following: farmer","images":[],"marking_scheme":"(i) Use of fertile forest land   (ii) Use of free forest land.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>6>c>ii","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"ii","group":"","topic":"FARMING SYSTEMS","question":"State two advantages of the system to each of the following: foresters.","images":[],"marking_scheme":"(i) Reduction in the cost of establishing plantation   (ii) Enrichment of soil nutrients whet leguminous food crops are planted.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>7","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"7","group":"","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Describe briefly the processses of egg formation in poultry.","images":[],"marking_scheme":"The process of egg formation in poultry is controlled by hormones. The egg is formed partly in the ovary and partly the oviduct. Yolk is formed In the ovary while other proteinous parts are formed in the liver and kidney. The yolk released by the ovary is taken up by infidibuIum and later moved to the oviduct where fertilization takes place The egg moves to the magnum, stay there for three hours and part of the albumen is formed. Chalaza is secreted round the yolk from the magnum. the egg moves to the isthmus where it stays for 1\u00bc hours and the two shell membrane, are formed. The shape of the egg is also formed in this region. The egg then, moves to the uterus where it slays for 19-20 hours, The Shell is formed in the uterus. The egg is then passed to the vagina where it stays for a very short time before it is laid","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>8","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"8","group":"","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"With the aid of a labelled diagram, describe digestion in a named ruminant.","images":["data:image/jpeg;base64,"],"marking_scheme":"Digestion in a ruminant such as in Cattle: When the cattle feeds, it folds the grass, chews it minimal) and swallows. The food gets to the rumen through the oesophagus by peristalsis. Micro-organisms in the rumen act on the grass. The cattle rests quietly an regurgitates the food back to the mouth through the reticulum by anti-peristaltic movement where the food is properly re-chewed in the mouth. After chewing,t cud is re-swallowed and the food goes to the omasum and later to the abomasum where enzymes are secret on the food. The digested food is absorbed into t body through the villi while the undigested ones a passed into the large intestine from where they are r moved as feaces or dung through the anus.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>9>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Write short notes on the following in agricultural production    land","images":[],"marking_scheme":"Land:  (i) Land refers to where production can take place. (ii) It s the gift of nature (iii) It Is immobile and deteriorates when it ts not properly used. (v) It also refers to soil,water.minerals (v) The reward for land is rent,","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>9>b","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Write short notes on the following in agricultural production  capital","images":[],"marking_scheme":"Capital; (i) This includes all man-made productive assets which are used in production. (i) It could be fixed, e.g. buildings, vehicles, tools and implements. (iii) It could be working capital e.g. water, feed, drug et.c (iv) The reward for capital is interest.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>9>c","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Write short notes on the following in agricultural production  labour","images":[],"marking_scheme":"Labour: (I) It refers to human effort put into production (ii) it includes personal, family, communal and hired or paid labour. (iii) Labour can be skilled, unkilled or semi-skilled. (iv) The reward for labour is wages or Salary.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>9>d","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"d","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"Write short notes on the following in agricultural production  farm manager.","images":[],"marking_scheme":"Entrepreneur or Management: (i) This refers to the person who coordinates, organises and controls the use of other factors of production, (iii) In agriculture, he is referred to as the Farm Manager.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>10>a","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Define the terms demand and supply and state the law governing them.","images":[],"marking_scheme":"Demand is defined as the quantity of a commodity which the consumers are willing and able buy at a given price at a time.The Law of demand states that the higher the price of a commodity, the lower the quantity that will be demanded, or the lower the price, the high the quantity of that commodity that will be demanded.    Supply is defined as the quantity of goods which the producers are able and willing to offer for sale at a given price over a period of time. The law of supply states that the higher the price of a commodity, the greater the quantity that will be supplied or the lower the price, the smaller the quantity of goods that will be supplied.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science>1994>10>b","subject":"Agricultural Science","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Explain the implications of demand and supply on agricultural production","images":[],"marking_scheme":"(1) When the demand for a farm produce is higher than suppl prices would tend to rise and farmers would be encouraged to produce more of such goods.    (2) But when the demand is lower than supply, prices would fall and the farmers would not be encouraged to produce.    (3) When the price a demand of a commodity are low, producers would also be discouraged from production","marks":"1","difficulty":"2"}];